import {
  useEffect,
  useState,
} from 'react'

interface TaskCardProps {
  id?: string | number
  title: string
  description: string
  priority?: string
  completed?: boolean

  category?: string
  tags?: string[]
  dueDate?: string
  onToggle?: () => void
  onDelete?: (id: string | number) => void

  onUpdateTask?: (
    id: string | number,
    updates: {
      title: string
      description: string
      priority: string
    }
  ) => void

  editingId?: string | number | null

  setEditingId?: (
    id: string | number | null
  ) => void
}

export default function TaskCard({
  id,
  title,
  description,
  priority = 'Medium',
  completed = false,
  category = 'General',
  tags = [],
  dueDate,
  onToggle,
  onDelete,
  onUpdateTask,
  editingId,
  setEditingId,
}: TaskCardProps) {
  const isEditing =
    editingId !== undefined &&
    editingId !== null &&
    editingId === id

  const [editTitle, setEditTitle] =
    useState(title)

  const [
    editDescription,
    setEditDescription,
  ] = useState(description)

  const [
    editPriority,
    setEditPriority,
  ] = useState(priority)

  useEffect(() => {
    if (isEditing) {
      setEditTitle(title)
      setEditDescription(description)
      setEditPriority(priority)
    }
  }, [
    isEditing,
    title,
    description,
    priority,
  ])

  const handleDelete = () => {
    if (
      id !== undefined &&
      onDelete &&
      window.confirm('Are you sure?')
    ) {
      onDelete(id)
    }
  }

  const handleSave = () => {
    if (
      id === undefined ||
      !onUpdateTask
    ) {
      return
    }

    const trimmedTitle =
      editTitle.trim()

    if (!trimmedTitle) {
      return
    }

    onUpdateTask(id, {
      title: trimmedTitle,
      description:
        editDescription,
      priority: editPriority,
    })

    setEditingId?.(null)
  }

  const handleCancel = () => {
    setEditTitle(title)
    setEditDescription(description)
    setEditPriority(priority)

    setEditingId?.(null)
  }

  const today =
  new Date()

today.setHours(
  0,
  0,
  0,
  0
)

const due =
  dueDate
    ? new Date(dueDate)
    : null

if (due) {
  due.setHours(
    0,
    0,
    0,
    0
  )
}

const isOverdue =
  !!due &&
  due < today &&
  !completed

const isDueToday =
  !!due &&
  due.getTime() ===
    today.getTime()

const isDueSoon =
  !!due &&
  !isOverdue &&
  !isDueToday &&
  due.getTime() -
    today.getTime() <=
    3 *
      24 *
      60 *
      60 *
      1000

  if (isEditing) {
    return (
      <article id="task-card">
        <input
          type="text"
          value={editTitle}
          onChange={(e) =>
            setEditTitle(
              e.target.value
            )
          }
        />

        <textarea
          value={editDescription}
          onChange={(e) =>
            setEditDescription(
              e.target.value
            )
          }
        />

        <select
          value={editPriority}
          onChange={(e) =>
            setEditPriority(
              e.target.value
            )
          }
        >
          <option value="High">
            High
          </option>

          <option value="Medium">
            Medium
          </option>

          <option value="Low">
            Low
          </option>
        </select>

        <button
          type="button"
          onClick={handleSave}
        >
          Save
        </button>

        <button
          type="button"
          onClick={handleCancel}
        >
          Cancel
        </button>
      </article>
    )
  }

  return (
    <article
      id="task-card"
      data-completed={completed}
      data-overdue={isOverdue}
      style={{
        backgroundColor: isOverdue
          ? '#fee2e2'
          : completed
          ? '#f3f4f6'
          : '',
      }}
    >
      {onToggle && (
        <input
          type="checkbox"
          checked={completed}
          onChange={onToggle}
        />
      )}

      <h2
        style={{
          textDecoration: completed
            ? 'line-through'
            : 'none',
        }}
      >
        {title}
      </h2>

      <p
        style={{
          textDecoration: completed
            ? 'line-through'
            : 'none',
        }}
      >
        {description}
      </p>

      <p>
        Priority: {priority}
      </p>

      <div id="task-category">
        {category}
      </div>

      <div id="task-tags">
        {tags.map((tag) => (
          <span
            key={tag}
            data-tag={tag}
            style={{
              display:
                'inline-block',
              marginRight: '6px',
              padding:
                '2px 8px',
              border:
                '1px solid #ccc',
              borderRadius:
                '999px',
            }}
          >
            {tag}
          </span>
        ))}
      </div>

      <button
        type="button"
        onClick={() =>
          setEditingId?.(
            id ?? null
          )
        }
      >
        Edit
      </button>

      {onDelete && (
        <button
          onClick={
            handleDelete
          }
        >
          Delete
        </button>
      )}
    </article>
  )
}

import {createContext,useContext,useState,useEffect,type ReactNode,} from 'react'
export type Theme = 'light' | 'dark'

export interface ThemeContextValue {
  theme: Theme
  setTheme: (theme: Theme) => void
  toggleTheme: () => void
}

export const ThemeContext = createContext<ThemeContextValue | null>(null)

export function ThemeProvider({
  children,
}: {
  children: ReactNode
}) {
  const [theme, setTheme] =
    useState<Theme>('light')

  useEffect(() => {
    const saved =
      localStorage.getItem(
        'task-app-theme'
      )

    if (
      saved === 'light' ||
      saved === 'dark'
    ) {
      setTheme(saved)
    }
  }, [])

  useEffect(() => {
    localStorage.setItem(
      'task-app-theme',
      theme
    )
  }, [theme])

  const toggleTheme = () => {
    setTheme((prev) =>
      prev === 'light'
        ? 'dark'
        : 'light'
    )
  }

  return (
    <ThemeContext.Provider
      value={{
        theme,
        setTheme,
        toggleTheme,
      }}
    >
      {children}
    </ThemeContext.Provider>
  )
}

export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext)
  if (!ctx) throw new Error('useTheme must be used within ThemeProvider')
  return ctx
}

import {createContext,useContext,type ReactNode,} from 'react'
import useLocalStorage from '../hooks/useLocalStorage'
export type Theme = 'light' | 'dark'

export interface ThemeContextValue {
  theme: Theme
  setTheme: (theme: Theme) => void
  toggleTheme: () => void
}

export const ThemeContext = createContext<ThemeContextValue | null>(null)

export function ThemeProvider({
  children,
}: {
  children: ReactNode
}) {
  const [theme, setTheme] =
  useLocalStorage<Theme>(
    'task-app-theme',
    'light'
  )

  const toggleTheme = () => {
    setTheme((prev) =>
      prev === 'light'
        ? 'dark'
        : 'light'
    )
  }

  return (
    <ThemeContext.Provider
      value={{
        theme,
        setTheme,
        toggleTheme,
      }}
    >
      {children}
    </ThemeContext.Provider>
  )
}

export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext)
  if (!ctx) throw new Error('useTheme must be used within ThemeProvider')
  return ctx
}

import React, {useEffect,useState,} from 'react'
import {ADD_TASK,UPDATE_TASK,DELETE_TASK,TOGGLE_TASK,} from '../reducers/taskReducer'
import TaskForm from './TaskForm'
import TaskList, { Task } from './TaskList'
import FilterBar from './FilterBar'
import StatsPanel from './StatsPanel'
import { useMemo } from 'react'
import { useTheme } from '../contexts/ThemeContext'
type FilterType =
  | 'all'
  | 'active'
  | 'completed'

type SortType =
  | 'recent'
  | 'high-low'
  | 'low-high'
  | 'alphabetical'
  | 'due-date'

interface TaskAppProps {
  tasks: Task[]
  dispatch?: React.Dispatch<any>

  showForm?: boolean
  countFormat?: string

  onDelete?: (id: string | number) => void
  showFilterBar?: boolean
  showStatsPanel?: boolean
  linkToTaskDetail?: boolean

  [key: string]: unknown
}

export default function TaskApp({
  tasks,
  dispatch,
  showForm,
  countFormat,
  onDelete,
  showFilterBar,
  showStatsPanel,
}: TaskAppProps) {
  const [filter, setFilter] =
    useState<FilterType>('all')

  const [sortOrder, setSortOrder] =
    useState<SortType>('recent')

  const [searchInput, setSearchInput] =
    useState('')

  const [search, setSearch] =
    useState('')

  const [isSearching, setIsSearching] =
    useState(false)

  const [editingId, setEditingId] =
    useState<string | number | null>(null)
  const {
    theme,
    toggleTheme,
  } = useTheme()
 
const [
  selectedCategory,
  setSelectedCategory,
] = useState(
  'All categories'
)

const categories = [
  ...new Set(
    tasks.map(
      (task) =>
        task.category ??
        'General'
    )
  ),
]
const stats = useMemo(() => {
  const total = tasks.length

  const completed =
    tasks.filter(
      (task) =>
        task.completed
    ).length

  const active =
    total - completed

  const overdue =
    tasks.filter(
      (task) => {
        if (
          !task.dueDate ||
          task.completed
        ) {
          return false
        }

        return (
          new Date(
            task.dueDate
          ) < new Date()
        )
      }
    ).length

  return {
    total,
    completed,
    active,
    overdue,
  }
}, [tasks])
  useEffect(() => {
    if (searchInput === search) {
      setIsSearching(false)
      return
    }

    setIsSearching(true)

    const timeoutId = window.setTimeout(
      () => {
        setSearch(searchInput)
        setIsSearching(false)
      },
      300
    )

    return () => {
      clearTimeout(timeoutId)
    }
  }, [searchInput, search])

  const handleAddTask = (
    task: Task
  ) => {
    dispatch?.({
      type: ADD_TASK,
      payload: task,
    })
  }

  const handleToggle = (
  id: string | number
) => {
  dispatch?.({
    type: TOGGLE_TASK,
    payload: id,
  })
}

  const handleDelete = (
  id: string | number
) => {
  dispatch?.({
    type: DELETE_TASK,
    payload: id,
  })
}

  const handleUpdateTask = (
    id: string | number,
    updates: {
      title: string
      description: string
      priority: string
    }
  ) => {
    dispatch?.({
  type: UPDATE_TASK,
  payload: {
    id,
    ...updates,
  },
})

setEditingId(null)

    setEditingId(null)
  }

  let filteredTasks = tasks

  if (filter === 'active') {
    filteredTasks =
      filteredTasks.filter(
        (task) =>
          !task.completed
      )
  }

  if (filter === 'completed') {
    filteredTasks =
      filteredTasks.filter(
        (task) =>
          task.completed
      )
  }

  if (
  selectedCategory !==
  'All categories'
) {
  filteredTasks =
    filteredTasks.filter(
      (task) =>
        task.category ===
        selectedCategory
    )
}

  if (search.trim()) {
    const searchLower =
      search.toLowerCase()

    filteredTasks =
      filteredTasks.filter(
        (task) =>
          task.title
            .toLowerCase()
            .includes(
              searchLower
            ) ||
          task.description
            .toLowerCase()
            .includes(
              searchLower
            )
      )
  }

  const priorityRank = {
    High: 3,
    Medium: 2,
    Low: 1,
  }

  const sortedTasks = [
    ...filteredTasks,
  ]

  if (sortOrder === 'high-low') {
    sortedTasks.sort(
      (a, b) =>
        priorityRank[
          b.priority as keyof typeof priorityRank
        ] -
        priorityRank[
          a.priority as keyof typeof priorityRank
        ]
    )
  }

  if (sortOrder === 'low-high') {
    sortedTasks.sort(
      (a, b) =>
        priorityRank[
          a.priority as keyof typeof priorityRank
        ] -
        priorityRank[
          b.priority as keyof typeof priorityRank
        ]
    )
  }

  if (
    sortOrder ===
    'alphabetical'
  ) {
    sortedTasks.sort((a, b) =>
      a.title
        .toLowerCase()
        .localeCompare(
          b.title.toLowerCase()
        )
    )
  }

  if (
  sortOrder ===
  'due-date'
) {
  sortedTasks.sort(
    (a, b) => {
      if (
        !a.dueDate &&
        !b.dueDate
      ) {
        return 0
      }

      if (!a.dueDate) {
        return 1
      }

      if (!b.dueDate) {
        return -1
      }

      return (
        new Date(
          a.dueDate
        ).getTime() -
        new Date(
          b.dueDate
        ).getTime()
      )
    }
  )
}

  const countText =
    showFilterBar
      ? `Showing ${sortedTasks.length} of ${tasks.length} tasks`
      : countFormat ===
          'completed'
        ? `${
            tasks.filter(
              (task) =>
                task.completed
            ).length
          } of ${
            tasks.length
          } completed`
        : `${tasks.length} Tasks`

  return (
  <div
    data-theme={theme}
    style={{
      backgroundColor:
        theme === 'dark'
          ? '#1f2937'
          : '#ffffff',
      color:
        theme === 'dark'
          ? '#ffffff'
          : '#000000',
      minHeight: '100vh',
    }}
  >
    <button
      id="theme-toggle"
      type="button"
      onClick={toggleTheme}
    >
      {theme === 'light'
        ? 'Dark Mode'
        : 'Light Mode'}
    </button>
      {showForm && (
        <TaskForm
          onAddTask={
            handleAddTask
          }
        />
      )}

      {showFilterBar && (
        <>
          <FilterBar
  filter={filter}
  onFilterChange={
    setFilter
  }
  sortOrder={sortOrder}
  onSortChange={
    setSortOrder
  }
  search={searchInput}
  onSearchChange={
    setSearchInput
  }
  categories={categories}
  selectedCategory={
    selectedCategory
  }
  onCategoryChange={
    setSelectedCategory
  }
/>

          {isSearching && (
            <div id="searching-indicator">
              Searching...
            </div>
          )}
        </>
      )}

      {showFilterBar &&
        sortedTasks.length ===
          0 && (
          <div id="filter-empty-message">
            No tasks found
          </div>
        )}
      {showStatsPanel && (
        <StatsPanel
          total={stats.total}
          completed={
            stats.completed
          }
          active={stats.active}
          overdue={stats.overdue}
      />
      )}
      <TaskList
        tasks={sortedTasks}
        countText={countText}
        onToggle={
          handleToggle
        }
        onDelete={
          onDelete ??
          handleDelete
        }
        onUpdateTask={
          handleUpdateTask
        }
        editingId={
          editingId
        }
        setEditingId={
          setEditingId
        }
      />
    </div>
  )
}
